package com.example;

import java.io.FileOutputStream;
import java.io.IOException;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.Properties;

public class BuildInfoGenerator {
    public static void main(String[] args) {
        if (args.length < 2) {
            System.err.println("Usage: BuildInfoGenerator <version> <outputFile>");
            System.exit(1);
        }

        String version = args[0];
        String outputFile = args[1];

        Properties props = new Properties();
        props.setProperty("build.version", version);
        props.setProperty("build.timestamp", LocalDateTime.now().format(DateTimeFormatter.ISO_DATE_TIME));
        props.setProperty("build.user", System.getProperty("user.name"));
        props.setProperty("build.java.version", System.getProperty("java.version"));

        try (FileOutputStream fos = new FileOutputStream(outputFile)) {
            props.store(fos, "Build Information");
            System.out.println("Build info generated: " + outputFile);
        } catch (IOException e) {
            System.err.println("Failed to generate build info: " + e.getMessage());
            System.exit(1);
        }
    }
}